#![allow(clippy::format_push_string)]

//! Generate admin entity registry (TypeScript) from API modules.

use std::fs;
use std::path::Path;

use crate::servers::config::Config;
use crate::servers::generators::ipc::ts_command_name;
use crate::servers::parse::ApiModule;
use crate::servers::types::{extract_input_type, inner_type, rust_type_to_ts, snake_to_camel};

/// Generate admin entity registry and write to the output file.
pub fn generate(output: &Path, modules: &[ApiModule], config: &Config) {
    let mut out = String::new();
    out.push_str(
        "// Auto-generated admin registry. DO NOT EDIT.\n\
         // Generated by ontogen from API source files.\n\n",
    );

    // Collect CRUD entities only
    let crud_modules: Vec<&ApiModule> = modules
        .iter()
        .filter(|m| {
            let fns: Vec<&str> = m.functions.iter().map(|f| f.name.as_str()).collect();
            fns.contains(&"list")
                && fns.contains(&"get_by_id")
                && fns.contains(&"create")
                && fns.contains(&"update")
                && fns.contains(&"delete")
        })
        .collect();

    out.push_str(
        "\
export interface AdminEntityConfig {
  /** Module key, e.g. 'node' */
  key: string
  /** URL-safe plural, e.g. 'nodes' */
  plural: string
  /** Human label, e.g. 'Node' */
  label: string
  /** Human plural label, e.g. 'Nodes' */
  pluralLabel: string
  /** ID type: always 'string' */
  idType: 'string'
  /** Transport method name for list */
  listMethod: string
  /** Transport method name for get by id */
  getMethod: string
  /** Transport method name for create */
  createMethod: string
  /** Transport method name for update */
  updateMethod: string
  /** Transport method name for delete */
  deleteMethod: string
  /** TypeScript return type name from bindings (for list items) */
  returnType: string
  /** TypeScript create input type name from bindings */
  createInputType: string
  /** TypeScript update input type name from bindings */
  updateInputType: string
}

",
    );

    out.push_str("export const adminEntities: AdminEntityConfig[] = [\n");

    for m in &crud_modules {
        let module = &m.name;
        let plural = config.naming.module_plural(module);

        let id_type = "string";

        let get_method = format!("get_{}_by_id", config.naming.url_singular(module));

        let list_fn = m.functions.iter().find(|f| f.name == "list").unwrap();
        let return_type_raw = inner_type(&list_fn.return_type);
        let return_type = rust_type_to_ts(&return_type_raw);

        let create_fn = m.functions.iter().find(|f| f.name == "create").unwrap();
        let create_input = rust_type_to_ts(&extract_input_type(&create_fn.params[0].ty));

        let update_fn = m.functions.iter().find(|f| f.name == "update").unwrap();
        let update_input = rust_type_to_ts(&extract_input_type(&update_fn.params[1].ty));

        let label = config.naming.label(module);
        let plural_label = config.naming.plural_label(module);

        out.push_str(&format!(
            "\
  {{
    key: '{module}',
    plural: '{plural}',
    label: '{label}',
    pluralLabel: '{plural_label}',
    idType: '{id_type}',
    listMethod: '{list_method}',
    getMethod: '{get_method}',
    createMethod: '{create_method}',
    updateMethod: '{update_method}',
    deleteMethod: '{delete_method}',
    returnType: '{return_type}',
    createInputType: '{create_input}',
    updateInputType: '{update_input}',
  }},\n",
            list_method = snake_to_camel(&ts_command_name(module, list_fn, config)),
            get_method = snake_to_camel(&get_method),
            create_method = snake_to_camel(&ts_command_name(module, create_fn, config)),
            update_method = snake_to_camel(&ts_command_name(module, update_fn, config)),
            delete_method = snake_to_camel(&ts_command_name(
                module,
                m.functions.iter().find(|f| f.name == "delete").unwrap(),
                config,
            )),
        ));
    }

    out.push_str("];\n\n");

    out.push_str(
        "\
export const adminEntityMap: Record<string, AdminEntityConfig> = Object.fromEntries(
  adminEntities.map((e) => [e.key, e]),
);\n\n\
export const adminEntityByPlural: Record<string, AdminEntityConfig> = Object.fromEntries(
  adminEntities.map((e) => [e.plural, e]),
);\n",
    );

    if let Some(parent) = output.parent() {
        fs::create_dir_all(parent).expect("Failed to create output directory");
    }
    fs::write(output, out).expect("Failed to write admin registry");
}
